    }
    console.log(`commit ${current}`);
    console.log(`Date: ${timestamp}`);
    console.log(`Message: ${message}`);
    console.log('');
    current = parentVal === 'NONE' ? null : parentVal;
  }
}

function parseCommit(hash) {
  const commitPath = path.join(COMMITS_DIR, hash);
  if (!fs.existsSync(commitPath)) return null;
  const content = fs.readFileSync(commitPath, 'utf8');
  let parent = '', timestamp = '', message = '';
  const files = {};
  let inFiles = false;
  for (const line of content.split('\n')) {
    if (line.startsWith('parent: ')) { parent = line.slice(8); inFiles = false; }
    else if (line.startsWith('timestamp: ')) { timestamp = line.slice(11); inFiles = false; }
    else if (line.startsWith('message: ')) { message = line.slice(9); inFiles = false; }
    else if (line === 'files:') { inFiles = true; }
    else if (inFiles && line.trim()) {
      const idx = line.lastIndexOf(' ');
      const fname = line.slice(0, idx);
      const blobhash = line.slice(idx + 1);
      files[fname] = blobhash;
    }
  }
  return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
  const c1 = parseCommit(hash1);
  const c2 = parseCommit(hash2);
  if (!c1 || !c2) {
    console.log('Invalid commit');
    process.exit(1);
  }
  const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
  const sorted = [...allFiles].sort();
  for (const f of sorted) {
    if (!(f in c1.files) && f in c2.files) {
      console.log(`Added: ${f}`);
    } else if (f in c1.files && !(f in c2.files)) {
      console.log(`Removed: ${f}`);
    } else if (c1.files[f] !== c2.files[f]) {
      console.log(`Modified: ${f}`);
    }
  }
}

function cmdCheckout(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  for (const [fname, blobhash] of Object.entries(commit.files)) {
    const blobContent = fs.readFileSync(path.join(OBJECTS_DIR, blobhash));
    fs.writeFileSync(fname, blobContent);
  }
  fs.writeFileSync(HEAD_FILE, hash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Checked out ${hash}`);
}

function cmdReset(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  fs.writeFileSync(HEAD_FILE, hash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Reset to ${hash}`);
}

function cmdRm(filename) {
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  if (!entries.includes(filename)) {
    console.log('File not in index');
    process.exit(1);
  }
  const newEntries = entries.filter(e => e !== filename);
  fs.writeFileSync(INDEX_FILE, newEntries.length ? newEntries.join('\n') + '\n' : '');
}

function cmdShow(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  console.log(`commit ${hash}`);
  console.log(`Date: ${commit.timestamp}`);
  console.log(`Message: ${commit.message}`);
  console.log('Files:');
  const sorted = Object.keys(commit.files).sort();
  for (const f of sorted) {
    console.log(`  ${f} ${commit.files[f]}`);
  }
}

