#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const MINIGIT_DIR = '.minigit';
const OBJECTS_DIR = path.join(MINIGIT_DIR, 'objects');
const COMMITS_DIR = path.join(MINIGIT_DIR, 'commits');
const INDEX_FILE = path.join(MINIGIT_DIR, 'index');
const HEAD_FILE = path.join(MINIGIT_DIR, 'HEAD');

function minihash(data) {
  let h = 1469598103934665603n;
  for (let i = 0; i < data.length; i++) {
    h ^= BigInt(data[i]);
    h = (h * 1099511628211n) % (1n << 64n);
  }
  return h.toString(16).padStart(16, '0');
}

function cmdInit() {
  if (fs.existsSync(MINIGIT_DIR)) {
    console.log('Repository already initialized');
    return;
  }
  fs.mkdirSync(OBJECTS_DIR, { recursive: true });
  fs.mkdirSync(COMMITS_DIR, { recursive: true });
  fs.writeFileSync(INDEX_FILE, '');
  fs.writeFileSync(HEAD_FILE, '');
}

function cmdAdd(filename) {
  if (!filename) {
    console.error('Usage: minigit add <file>');
    process.exit(1);
  }
  if (!fs.existsSync(filename)) {
    console.log('File not found');
    process.exit(1);
  }
  const content = fs.readFileSync(filename);
  const hash = minihash(content);
  fs.writeFileSync(path.join(OBJECTS_DIR, hash), content);

  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  if (!entries.includes(filename)) {
    entries.push(filename);
    fs.writeFileSync(INDEX_FILE, entries.join('\n') + '\n');
  }
}

function cmdCommit(message) {
  if (!message) {
    console.error('Usage: minigit commit -m "<message>"');
    process.exit(1);
  }
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  if (entries.length === 0) {
    console.log('Nothing to commit');
    process.exit(1);
  }

  const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  const parent = head || 'NONE';
  const timestamp = Math.floor(Date.now() / 1000);

  const sortedFiles = [...entries].sort();
  const fileLines = sortedFiles.map(f => {
    const content = fs.readFileSync(f);
    const hash = minihash(content);
    return `${f} ${hash}`;
  }).join('\n');

  const commitContent = `parent: ${parent}\ntimestamp: ${timestamp}\nmessage: ${message}\nfiles:\n${fileLines}\n`;
  const commitHash = minihash(Buffer.from(commitContent));

  fs.writeFileSync(path.join(COMMITS_DIR, commitHash), commitContent);
  fs.writeFileSync(HEAD_FILE, commitHash);
  fs.writeFileSync(INDEX_FILE, '');

  console.log(`Committed ${commitHash}`);
}

function cmdStatus() {
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  console.log('Staged files:');
  if (entries.length === 0) {
    console.log('(none)');
  } else {
    for (const e of entries) {
      console.log(e);
    }
  }
}

function cmdLog() {
  const head = fs.readFileSync(HEAD_FILE, 'utf8').trim();
  if (!head) {
    console.log('No commits');
    return;
  }

  let current = head;
  while (current && current !== 'NONE') {
    const commitPath = path.join(COMMITS_DIR, current);
    const content = fs.readFileSync(commitPath, 'utf8');
    let parentVal = '', timestamp = '', message = '';
    for (const line of content.split('\n')) {
      if (line.startsWith('parent: ')) parentVal = line.slice(8);
      else if (line.startsWith('timestamp: ')) timestamp = line.slice(11);
      else if (line.startsWith('message: ')) message = line.slice(9);
    }
    console.log(`commit ${current}`);
    console.log(`Date: ${timestamp}`);
    console.log(`Message: ${message}`);
    console.log('');
    current = parentVal === 'NONE' ? null : parentVal;
  }
}

function parseCommit(hash) {
  const commitPath = path.join(COMMITS_DIR, hash);
  if (!fs.existsSync(commitPath)) return null;
  const content = fs.readFileSync(commitPath, 'utf8');
  let parent = '', timestamp = '', message = '';
  const files = {};
  let inFiles = false;
  for (const line of content.split('\n')) {
    if (line.startsWith('parent: ')) { parent = line.slice(8); inFiles = false; }
    else if (line.startsWith('timestamp: ')) { timestamp = line.slice(11); inFiles = false; }
    else if (line.startsWith('message: ')) { message = line.slice(9); inFiles = false; }
    else if (line === 'files:') { inFiles = true; }
    else if (inFiles && line.trim()) {
      const idx = line.lastIndexOf(' ');
      const fname = line.slice(0, idx);
      const blobhash = line.slice(idx + 1);
      files[fname] = blobhash;
    }
  }
  return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
  const c1 = parseCommit(hash1);
  const c2 = parseCommit(hash2);
  if (!c1 || !c2) {
    console.log('Invalid commit');
    process.exit(1);
  }
  const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
  const sorted = [...allFiles].sort();
  for (const f of sorted) {
    if (!(f in c1.files) && f in c2.files) {
      console.log(`Added: ${f}`);
    } else if (f in c1.files && !(f in c2.files)) {
      console.log(`Removed: ${f}`);
    } else if (c1.files[f] !== c2.files[f]) {
      console.log(`Modified: ${f}`);
    }
  }
}

function cmdCheckout(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  for (const [fname, blobhash] of Object.entries(commit.files)) {
    const blobContent = fs.readFileSync(path.join(OBJECTS_DIR, blobhash));
    fs.writeFileSync(fname, blobContent);
  }
  fs.writeFileSync(HEAD_FILE, hash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Checked out ${hash}`);
}

function cmdReset(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  fs.writeFileSync(HEAD_FILE, hash);
  fs.writeFileSync(INDEX_FILE, '');
  console.log(`Reset to ${hash}`);
}

function cmdRm(filename) {
  const index = fs.readFileSync(INDEX_FILE, 'utf8');
  const entries = index ? index.split('\n').filter(e => e !== '') : [];
  if (!entries.includes(filename)) {
    console.log('File not in index');
    process.exit(1);
  }
  const newEntries = entries.filter(e => e !== filename);
  fs.writeFileSync(INDEX_FILE, newEntries.length ? newEntries.join('\n') + '\n' : '');
}

function cmdShow(hash) {
  const commit = parseCommit(hash);
  if (!commit) {
    console.log('Invalid commit');
    process.exit(1);
  }
  console.log(`commit ${hash}`);
  console.log(`Date: ${commit.timestamp}`);
  console.log(`Message: ${commit.message}`);
  console.log('Files:');
  const sorted = Object.keys(commit.files).sort();
  for (const f of sorted) {
    console.log(`  ${f} ${commit.files[f]}`);
  }
}

// Main
const args = process.argv.slice(2);
const command = args[0];

switch (command) {
  case 'init':
    cmdInit();
    break;
  case 'add':
    cmdAdd(args[1]);
    break;
  case 'commit':
    if (args[1] === '-m') {
      cmdCommit(args[2]);
    } else {
      console.error('Usage: minigit commit -m "<message>"');
      process.exit(1);
    }
    break;
  case 'log':
    cmdLog();
    break;
  default:
    console.error('Unknown command');
    process.exit(1);
}
